class Solution {
    public int hardestWorker(int n, int[][] logs) {
        int maxTime = 0;
        int hardestWorkerId = 0;
        int prevEndTime = 0;

        for (int[] log : logs) {
            int taskTime = log[1] - prevEndTime;
            prevEndTime = log[1];

            if (taskTime > maxTime) {
                maxTime = taskTime;
                hardestWorkerId = log[0];
            } else if (taskTime == maxTime) {
                hardestWorkerId = Math.min(hardestWorkerId, log[0]);
            }
        }

        return hardestWorkerId;
    }
}
```
